const dados = $json;
let anexos = [];

// Converte a string de anexos de volta para Array, se necessário
try {
  anexos = typeof dados.anexos === 'string' ? JSON.parse(dados.anexos) : (dados.anexos || []);
} catch (e) {
  anexos = [];
}

// LIMPEZA DO BASE64 (Remove o prefixo data:image/... caso o WhatsApp envie)
anexos = anexos.map(a => {
  let b64 = a.base64 || a.conteudo_base64 || '';
  if (b64.includes(',')) {
    b64 = b64.split(',')[1];
  }
  return { ...a, base64: b64 };
});

const tem_imagem = anexos.some(a => ['jpg','jpeg','png','webp','gif','bmp'].includes((a.tipo||'').toLowerCase()) && a.base64);
const tem_pdf    = anexos.some(a => (a.tipo||'').toLowerCase() === 'pdf');
const tem_excel  = anexos.some(a => ['xlsx','xls','csv'].includes((a.tipo||'').toLowerCase()));
const tem_audio  = anexos.some(a => ['ogg','mp3','wav','m4a','opus'].includes((a.tipo||'').toLowerCase()));

// FIX v2: Contadores para debugging
const count_imagens = anexos.filter(a => ['jpg','jpeg','png','webp','gif','bmp'].includes((a.tipo||'').toLowerCase()) && a.base64).length;
const count_pdfs    = anexos.filter(a => (a.tipo||'').toLowerCase() === 'pdf').length;
const count_excels  = anexos.filter(a => ['xlsx','xls','csv'].includes((a.tipo||'').toLowerCase())).length;
const count_audios  = anexos.filter(a => ['ogg','mp3','wav','m4a','opus'].includes((a.tipo||'').toLowerCase())).length;

return { 
  json: { 
    ...dados, 
    anexos: anexos, 
    tipos_anexos: { tem_imagem, tem_pdf, tem_excel, tem_audio },
    contagem_anexos: { count_imagens, count_pdfs, count_excels, count_audios, total: anexos.length },
    precisa_preprocessamento: (tem_imagem || tem_pdf || tem_excel || tem_audio)
  } 
};

// ═══════════════════════════════════════════════════════════════
// FIX v2: Suporte a MÚLTIPLOS PDFs
// Consolida texto de 3 fontes:
//   A) Campo texto_pdf pré-extraído pelo WF1 (string direta)
//   B) Campo texto dentro de cada item do array anexos
//   C) Fallback: nome do arquivo como referência
// ═══════════════════════════════════════════════════════════════
const dados = $('Tem PDF?').first().json;
let textosAcumulados = [];

// Fonte A: texto_pdf já enviado pelo WF1
const textoPdfWF1 = $json.texto_pdf || $json.text || $json.content || '';
if (textoPdfWF1.trim()) {
  textosAcumulados.push(textoPdfWF1.trim());
}

// Fonte B: PDFs com texto pre-extraído dentro do array de anexos
let anexos = [];
try {
  anexos = typeof dados.anexos === 'string' ? JSON.parse(dados.anexos) : (dados.anexos || []);
} catch(e) { anexos = []; }

const pdfs = anexos.filter(a => (a.tipo || '').toLowerCase() === 'pdf');

for (let i = 0; i < pdfs.length; i++) {
  const pdf = pdfs[i];
  const nomeArquivo = pdf.nome || pdf.filename || `PDF ${i+1}`;

  if (pdf.texto && pdf.texto.trim()) {
    // PDF já tem texto extraído (enviado pelo WF1)
    const textoNormalizado = pdf.texto.trim();
    if (!textosAcumulados.includes(textoNormalizado)) {
      const prefixo = pdfs.length > 1 ? `[PDF ${i+1}: ${nomeArquivo}]\n` : '';
      textosAcumulados.push(prefixo + textoNormalizado);
    }
  } else if (pdf.base64 && !textoPdfWF1.trim()) {
    // PDF com base64 mas sem texto extraído — WF1 deveria ter feito a extração.
    // Anotamos para o IA saber que havia um PDF não processado.
    textosAcumulados.push(`[PDF ${i+1}: "${nomeArquivo}" recebido como base64 — extração de texto requer processamento adicional no WF1 via pdfjs/Textract]`);
  }
}

const textoPdfFinal = textosAcumulados.join('\n\n─────────────────\n\n').substring(0, 8000);

return { json: { ...dados, texto_pdf: textoPdfFinal } };

// ═══════════════════════════════════════════════════════════════
// FIX v2: Parsear Excel — passa o texto já processado pelo
// nó 'Code in JavaScript2' sem tentar re-construí-lo.
// O bug original criava uma tabela com os campos do JSON como
// se fossem colunas de dados, corrompendo o resultado.
// ═══════════════════════════════════════════════════════════════
