// ═══════════════════════════════════════════════════════════════
// FIX v2: Processar TODOS os Áudios via Groq Whisper
// Substitui o nó HTTP anterior que só processava 1 áudio
// e exigia dados binários (incompatível com base64 do WhatsApp).
// Este nó usa axios + FormData para enviar cada áudio.
//
// CONFIGURAÇÃO: Define a variável de ambiente GROQ_API_KEY
// no n8n (Settings → Environment Variables) OU substitui
// o valor abaixo pela tua chave diretamente.
// ═══════════════════════════════════════════════════════════════
const axios = require('axios');
const FormData = require('form-data');

// ── Chave Groq (usa variável de ambiente por segurança) ──
const GROQ_API_KEY = $env.GROQ_API_KEY || 'SUBSTITUI_PELA_TUA_GROQ_API_KEY';

const dados = { ...$json };
let texto_acumulado = '';

// ── 1. Extrair todos os áudios ──
let anexos = [];
try {
  anexos = typeof dados.anexos === 'string' ? JSON.parse(dados.anexos) : (dados.anexos || []);
} catch(e) { anexos = []; }

const audios = anexos.filter(a =>
  ['ogg', 'mp3', 'wav', 'm4a', 'opus'].includes((a.tipo || '').toLowerCase()) && a.base64
);

if (audios.length === 0) {
  const output = { ...dados };
  output.texto_audio = '';
  return [{ json: output }];
}

// ── 2. Processar cada áudio sequencialmente ──
const mimeMap = {
  ogg:  'audio/ogg',
  mp3:  'audio/mpeg',
  wav:  'audio/wav',
  m4a:  'audio/mp4',
  opus: 'audio/opus'
};

for (let i = 0; i < audios.length; i++) {
  const audio = audios[i];
  const nomeArquivo = audio.nome || audio.filename || `audio_${i+1}`;

  try {
    // Limpar e decodificar base64
    let b64 = (audio.base64 || '').replace(/\s/g, '');
    if (b64.includes(',')) b64 = b64.split(',')[1];
    if (!b64) {
      texto_acumulado += `\n[Áudio ${i+1}: base64 vazio ou inválido]`;
      continue;
    }

    const tipo = (audio.tipo || 'ogg').toLowerCase();
    const mimeType = mimeMap[tipo] || 'audio/ogg';
    const ext = tipo;
    const buffer = Buffer.from(b64, 'base64');
    b64 = null; // Libera memória imediatamente

    // Construir FormData
    const form = new FormData();
    form.append('file', buffer, {
      filename: `${nomeArquivo.replace(/\.[^.]+$/, '')}.${ext}`,
      contentType: mimeType
    });
    form.append('model',           'whisper-large-v3-turbo');
    form.append('temperature',     '0');
    form.append('response_format', 'verbose_json');
    form.append('language',        'pt');

    const response = await axios.post(
      'https://api.groq.com/openai/v1/audio/transcriptions',
      form,
      {
        headers: {
          ...form.getHeaders(),
          'Authorization': `Bearer ${GROQ_API_KEY}`
        },
        timeout: 120000,
        maxBodyLength: Infinity,
        maxContentLength: Infinity
      }
    );

    const transcricao = response.data.text || '';
    if (transcricao.trim()) {
      const prefixo = audios.length > 1
        ? `[Áudio ${i+1}: ${nomeArquivo}]\n`
        : '';
      texto_acumulado += (texto_acumulado ? '\n\n─────────────────\n\n' : '') + prefixo + transcricao.trim();
    }

  } catch (err) {
    const status = err.response?.status || 'sem status';
    const msg    = err.response?.data?.error?.message || err.response?.data?.message || err.message;
    texto_acumulado += `\n[Erro Áudio ${i+1} (${nomeArquivo}) | HTTP ${status}: ${msg}]`;
  }

  // Pausa entre requisições para não sobrecarregar a API
  if (i < audios.length - 1) {
    await new Promise(r => setTimeout(r, 500));
  }
}

// ── 3. Retorno limpo ──
const output = { ...dados };
delete output.message_raw; // Remove campos pesados
output.texto_audio = texto_acumulado;

return [{ json: output }];

// FIX v2: O nó 'Processar Todos os Áudios' já retorna
// o texto acumulado de TODOS os áudios em 'texto_audio'.
// Este nó apenas garante que o campo está presente e
// mantém compatibilidade com o fluxo descendente.
const transcricao = $json.texto_audio || '';
return { json: { ...$json, texto_audio: transcricao } };

const original = $json.texto || '';
const ocr   = $json.texto_ocr || '';
const pdf   = $json.texto_pdf || '';
const excel = $json.texto_excel || '';
