// 1. Busca os dados originais do nó "Switch por Categoria"
const dadosOriginais = $('Switch por Categoria').first().json;

// 2. Obtém os dados do item que chegou a este nó (pode conter campos extras como 'itens' extraídos)
const itemAtual = $input.item.json;

// 3. Mescla os dois objetos (prioriza campos do itemAtual, se houver conflito)
