const axios = require('axios');

// 1. CONFIGURAÇÕES
const API_KEY = 'ppEa5Z2guZyMxcGo4y8L4eDr222Wyvdd';
const dados = $json;
let texto_acumulado = '';

// 2. EXTRAÇÃO E LIMPEZA
let anexos = [];
try {
  anexos = typeof dados.anexos === 'string' ? JSON.parse(dados.anexos) : (dados.anexos || []);
} catch (e) {
  anexos = [];
}

const imagens = anexos.filter(a =>
  ['jpg', 'jpeg', 'png', 'webp'].includes((a.tipo || '').toLowerCase()) && a.base64
);

if (imagens.length === 0) {
  return [{ json: { ...dados, texto_ocr: 'Nenhuma imagem encontrada' } }];
}

// 3. PROCESSAMENTO SEQUENCIAL
for (let i = 0; i < imagens.length; i++) {
  try {
    // Limpa o base64 e remove o prefixo se existir
    let b64 = imagens[i].base64.replace(/\s/g, '');
    if (b64.includes(',')) b64 = b64.split(',')[1];

    // Determina o mime type com base no campo "tipo"
    const tipo = (imagens[i].tipo || 'jpeg').toLowerCase();
    const mimeMap = { jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png', webp: 'image/webp' };
    const mimeType = mimeMap[tipo] || 'image/jpeg';

    // ✅ FORMATO CORRETO: type "image_url" com data URI completo
    const response = await axios.post(
      'https://api.mistral.ai/v1/ocr',
      {
        model: "mistral-ocr-latest",
        document: {
          type: "image_url",
          image_url: `data:${mimeType};base64,${b64}`
        }
      },
      {
        headers: {
          'Authorization': `Bearer ${API_KEY}`,
          'Content-Type': 'application/json'
        },
        timeout: 60000,
        maxBodyLength: Infinity,
        maxContentLength: Infinity
      }
    );

    // Limpeza de memória imediata
    b64 = null;
    imagens[i].base64 = null;

    if (response.data && response.data.pages) {
      const markdown = response.data.pages.map(p => p.markdown).join('\n');
      texto_acumulado += (texto_acumulado ? '\n\n' : '') + markdown;
    }

  } catch (err) {
    // Log detalhado do erro para debug
    const status = err.response?.status || 'sem status';
    const msg = err.response?.data?.message || err.response?.data?.detail || err.message;
    texto_acumulado += `\n[Erro Imagem ${i+1} | Status ${status}: ${msg}]`;
  }

  // Pausa entre requests para não sobrecarregar a API
  if (i < imagens.length - 1) {
    await new Promise(r => setTimeout(r, 300));
  }
}

// 4. RETORNO LIMPO (mantém anexos e message_raw, apenas limpa base64 das imagens)
const output = { ...dados };

// Opcional: remove base64 das imagens já processadas para reduzir payload
if (output.anexos && Array.isArray(output.anexos)) {
  output.anexos = output.anexos.map(a => {
    if (['jpg','jpeg','png','webp'].includes((a.tipo || '').toLowerCase())) {
      const { base64, ...rest } = a;
      return rest; // remove base64 da imagem
    }
    return a;
  });
}

output.texto_ocr = texto_acumulado;

// NÃO delete output.anexos;
// NÃO delete output.message_raw;

return [{ json: output }];

const axios = require('axios');
const XLSX  = require('xlsx');

const API_KEY = 'ppEa5Z2guZyMxcGo4y8L4eDr222Wyvdd';
const dados = { ...$json };

// ══════════════════════════════════════════════════════════════════════
// 1. EXTRACTOR DE BASE64 — 3 estratégias em cascata
//
// O problema: a Evolution API envia o array `anexos` com base64 vazio (""),
// mas coloca o conteúdo real dentro do message_raw com 3 níveis de escape:
//
//   message_raw (string)
//     └─ JSON.parse → [ "[\"...\"]", "[\"...\"]", ... ]  (array por mensagem)
//           └─ JSON.parse → [ "{\"documentMessage\":{...},\"base64\":\"...\"}" ]
//                 └─ JSON.parse → { documentMessage: {...}, base64: "UEsDB..." }
// ══════════════════════════════════════════════════════════════════════

let todosExcels = [];

// ── Estratégia A: array anexos com base64 preenchido (caso ideal) ──────
try {
  const lista = typeof dados.anexos === 'string'
    ? JSON.parse(dados.anexos)
    : (dados.anexos || []);

  const comBase64 = lista.filter(a =>
    ['xlsx', 'xls', 'csv'].includes((a.tipo || '').toLowerCase()) &&
    a.base64 && a.base64.trim() !== ''
  );

  if (comBase64.length > 0) todosExcels = comBase64;
} catch (e) {}

// ── Estratégia B: message_raw (Evolution API — 3 níveis de JSON) ────────
if (todosExcels.length === 0 && dados.message_raw) {
  try {
    // Nível 1: message_raw string → array de strings (uma por mensagem)
    const nivel1 = typeof dados.message_raw === 'string'
      ? JSON.parse(dados.message_raw)
      : dados.message_raw;

    const arrayNivel1 = Array.isArray(nivel1) ? nivel1 : [nivel1];

    for (const itemNivel1 of arrayNivel1) {
      try {
        // Nível 2: cada string → array de strings internas
        const nivel2 = typeof itemNivel1 === 'string'
          ? JSON.parse(itemNivel1)
          : itemNivel1;

        const arrayNivel2 = Array.isArray(nivel2) ? nivel2 : [nivel2];

        for (const itemNivel2 of arrayNivel2) {
          try {
            // Nível 3: cada string interna → objeto da mensagem real
            const msgObj = typeof itemNivel2 === 'string'
              ? JSON.parse(itemNivel2)
              : itemNivel2;

            // Verifica se é documento Excel
            const docMsg = msgObj.documentMessage;
            if (!docMsg) continue;

            const mime      = (docMsg.mimetype  || '').toLowerCase();
            const fileName  = (docMsg.fileName  || docMsg.title || '').toLowerCase();
            const b64       = msgObj.base64 || docMsg.base64 || '';

            const isExcel =
              mime.includes('spreadsheet') ||
              mime.includes('excel')       ||
              mime.includes('csv')         ||
              /\.(xlsx|xls|csv)$/.test(fileName);

            if (isExcel && b64.trim() !== '') {
              todosExcels.push({
                base64: b64,
                tipo:   mime.includes('csv') ? 'csv' : 'xlsx',
                nome:   docMsg.fileName || docMsg.title || 'documento.xlsx'
              });
            }
          } catch (e3) { continue; }
        }
      } catch (e2) { continue; }
    }
  } catch (e1) {}
}

// ── Estratégia C: base64 na raiz do JSON (fallback genérico) ───────────
if (todosExcels.length === 0 && dados.base64 && dados.base64.trim() !== '') {
  const tipo = (dados.tipo || 'xlsx').toLowerCase();
  if (['xlsx', 'xls', 'csv'].includes(tipo)) {
    todosExcels.push({
      base64: dados.base64,
      tipo,
      nome: dados.nome_arquivo || 'arquivo.xlsx'
    });
  }
}

if (todosExcels.length === 0) {
  throw new Error(
    'Base64 do Excel não encontrado em nenhuma das 3 estratégias (anexos, message_raw, raiz). ' +
    'Verifica se o message_raw está a ser enviado pelo WF anterior.'
  );
}

// ══════════════════════════════════════════════════════════════════════
// 2. PROCESSAR CADA FICHEIRO EXCEL ENCONTRADO
// ══════════════════════════════════════════════════════════════════════

let textoAcumulado = '';
const folhasAcumuladas = [];
const MAX_LINHAS = 100;

for (let idx = 0; idx < todosExcels.length; idx++) {
  const excelItem    = todosExcels[idx];
  const nomeArquivo  = excelItem.nome || `Excel ${idx + 1}`;

  try {
    // Limpar e decodificar base64
    let cleanB64 = (excelItem.base64 || '').replace(/\s/g, '');
    if (cleanB64.includes(',')) cleanB64 = cleanB64.split(',')[1];

    if (!cleanB64) {
      textoAcumulado += `\n[Excel ${idx+1} (${nomeArquivo}): base64 vazio após limpeza]`;
      continue;
    }

    let buffer = Buffer.from(cleanB64, 'base64');
    cleanB64 = null; // Libera memória

    // Ler workbook com SheetJS
    let workbook;
    try {
      workbook = XLSX.read(buffer, { type: 'buffer', cellDates: true });
    } catch (err) {
      textoAcumulado += `\n[Excel ${idx+1} (${nomeArquivo}): Ficheiro corrompido — ${err.message}]`;
      continue;
    }
    buffer = null;

    if (!workbook.SheetNames || workbook.SheetNames.length === 0) {
      textoAcumulado += `\n[Excel ${idx+1} (${nomeArquivo}): Nenhuma folha encontrada]`;
      continue;
    }

    // Converter cada folha para CSV
    let conteudoExcel = '';
    for (const nomeFolha of workbook.SheetNames) {
      const folha      = workbook.Sheets[nomeFolha];
      const dadosFolha = XLSX.utils.sheet_to_json(folha, {
        header: 1, defval: '', blankrows: false
      });
      if (dadosFolha.length === 0) continue;

      const dadosLimitados = dadosFolha.slice(0, MAX_LINHAS);
      const csv = XLSX.utils.sheet_to_csv(
        XLSX.utils.aoa_to_sheet(dadosLimitados),
        { blankrows: false }
      );

      folhasAcumuladas.push({
        arquivo:         nomeArquivo,
        nome:            nomeFolha,
        linhas_totais:   dadosFolha.length,
        linhas_enviadas: dadosLimitados.length
      });

      conteudoExcel += `### Ficheiro: "${nomeArquivo}" | Folha: "${nomeFolha}"\n\`\`\`csv\n${csv}\n\`\`\`\n\n`;
    }
    workbook = null;

    if (!conteudoExcel) {
      textoAcumulado += `\n[Excel ${idx+1} (${nomeArquivo}): Nenhum dado nas folhas]`;
      continue;
    }

    // ── Chamar Mistral para converter CSV em tabela Markdown limpa ──────
    let analise = '';
    try {
      const mistralResp = await axios.post(
        'https://api.mistral.ai/v1/chat/completions',
        {
          model: 'mistral-large-latest',
          messages: [
            {
              role: 'system',
              content: 'Responde exclusivamente com a tabela Markdown extraída do CSV. ' +
                       'Nada de textos, análises, metadados, linhas de separador, ' +
                       '[object Object] ou frases como "aqui estão". ' +
                       'Começa logo com | e termina na última linha da tabela.'
            },
            {
              role: 'user',
              content: `Analisa este ficheiro:\n\n${conteudoExcel}`
            }
          ],
          max_tokens:  4096,
          temperature: 0.1
        },
        {
          headers: {
            'Authorization': `Bearer ${API_KEY}`,
            'Content-Type':  'application/json'
          },
          timeout: 90000
        }
      );
      analise = mistralResp.data.choices[0].message.content;
    } catch (err) {
      const msg = err.response?.data?.message || err.response?.data?.detail || err.message;
      analise = `[Erro Mistral: ${msg}]`;
    }
    conteudoExcel = null;

    // Acumular resultado (com separador se houver múltiplos ficheiros)
    const prefixo = todosExcels.length > 1
      ? `**Ficheiro ${idx+1}: ${nomeArquivo}**\n\n`
      : '';
    textoAcumulado += (textoAcumulado ? '\n\n─────────────────\n\n' : '') + prefixo + analise;

  } catch (err) {
    textoAcumulado += `\n[Erro inesperado Excel ${idx+1} (${nomeArquivo}): ${err.message}]`;
  }

  // Pausa entre ficheiros para não sobrecarregar a API
  if (idx < todosExcels.length - 1) {
    await new Promise(r => setTimeout(r, 500));
  }
}

// ══════════════════════════════════════════════════════════════════════
// 3. RETORNO LIMPO — remove campos pesados para não crashar o n8n
// ══════════════════════════════════════════════════════════════════════

const output = { ...dados };
delete output.anexos;
delete output.message_raw;
delete output.base64;

output.texto_excel  = textoAcumulado;
output.folhas_excel = folhasAcumuladas;

return [{ json: output }];

// Dados originais completos (antes do Data Table o engolir)
const dadosOriginais = $('Code in JavaScript').first().json;  

// Dados da tabela (saída do Atualizar Canal Cliente)
const dadosTabela = $json;

// Junta tudo: mantém os originais e adiciona/sobrescreve com os da tabela
const dadosCompletos = {
  ...dadosOriginais,
  ...dadosTabela
};

return { json: dadosCompletos };

// Recebe todos os itens do workflow anterior
const items = $input.all();

// Inicializa objeto consolidado
let consolidated = {
  canal: null,
  remetente: null,
  assunto: "",
  texto: "",
  texto_pdf: "",
  anexos: [],
  message_raw: [],
  timestamp: null,
  ids: []
};

// Percorre os itens na ordem recebida (importante para rastreabilidade)
for (const item of items) {
  const data = item.json;

  // Preenche campos comuns (pega do primeiro que tiver valor)
  if (!consolidated.canal && data.canal) consolidated.canal = data.canal;
  if (!consolidated.remetente && data.remetente) consolidated.remetente = data.remetente;
  if (!consolidated.timestamp && data.timestamp) consolidated.timestamp = data.timestamp;

  // Concatena textos (preserva ordem)
  if (data.texto && data.texto.trim()) {
    consolidated.texto += (consolidated.texto ? " " : "") + data.texto.trim();
  }

  // Concatena texto_pdf (se houver)
  if (data.texto_pdf && data.texto_pdf.trim()) {
    consolidated.texto_pdf += (consolidated.texto_pdf ? "\n\n" : "") + data.texto_pdf.trim();
  }

  // Concatena anexos (preserva ordem)
  let anexosItem = [];
  try {
    anexosItem = typeof data.anexos === 'string' ? JSON.parse(data.anexos) : (data.anexos || []);
  } catch(e) { anexosItem = []; }

  consolidated.anexos.push(...anexosItem);

  // Concatena message_raw (útil para debug)
  if (data.message_raw) {
    let raw = typeof data.message_raw === 'string' ? data.message_raw : JSON.stringify(data.message_raw);
    consolidated.message_raw.push(raw);
  }

  // Concatena ids
  if (data.ids && Array.isArray(data.ids)) {
    consolidated.ids.push(...data.ids);
  }
}

// Remove duplicatas de anexos (baseado no nome + tipo + tamanho aproximado)
const uniqueAnexos = [];
const keys = new Set();
for (const anexo of consolidated.anexos) {
  const key = `${anexo.tipo}|${anexo.nome || ''}|${(anexo.base64 || '').length}`;
  if (!keys.has(key)) {
    keys.add(key);
    uniqueAnexos.push(anexo);
  }
}
consolidated.anexos = uniqueAnexos;

// Garante que message_raw seja string (opcional)
consolidated.message_raw = consolidated.message_raw.length ? JSON.stringify(consolidated.message_raw) : "";

return [{ json: consolidated }];
